final:
module RefModule(
    input [1:0] in1,
    input [2:0] in2,
    input in3,
    input [3:0] in4,
    input [1:0] in5,
    output out1
);

  wire temp1_(in1 >= 2) | (in2 >= 4) | (in3) = (in1 >= 2) | (in2 >= 4) | (in3);
  wire temp2_((in4 + in5) >= 5) = ((in4 + in5) >= 5);
  assign out1 = temp1_(in1 >= 2) | (in2 >= 4) | (in3) | temp2_((in4 + in5) >= 5);

endmodule
